proof_block:
// The synthetic ensures has implication form
//   H(pre, post1, post2) ==> det_set_equal(r1, r2, post1, post2)
// where `det_set_equal` is `(r1 == r2) && (post1_self_ == post2_self_)`.
// `r1`, `r2` are unit, so the load-bearing conjunct is full
// `Array<A,N>` structural equality, which decomposes field-wise into
//   (a) post1.seq === post2.seq      (Ghost<Seq<A>>)
//   (b) post1.ar  === post2.ar       ([A;N])
//
// (a) follows by Seq extensionality through the shared update target.
// (b) is driven via `axiom_array_ext_equal` (the only `==`-related
//     axiom on `[A;N]`).  `lemma_array_index` (in `group_array_axioms`)
//     bridges the indexing operator to the `View` impl of `[A;N]`
//     (i.e. `a[j] == a.view()[j]`), and the inline `Array::view`
//     definition `self@ == self.seq@` propagates the seq equality from
//     (a) into the per-entry equality of `ar`.
//
// Wrapping in `if H { ... }` records every inner fact as
// `H ==> fact` — exactly the shape the implication-form synthetic
// ensures consumes (the PageAllocator `det_*` template).  The previous
// attempt only emitted seq-equality tautologies and `r1 == r2`, leaving
// the `ar` field entirely unaddressed; this attempt closes that gap by
// also discharging field (b).

broadcast use vstd::array::group_array_axioms;

if ({
    &&& (post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    &&& (post1_self_.wf())
    &&& (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    &&& (post2_self_.wf())
}) {
    // (1) Seq extensionality chained through the shared update target,
    //     then lifted to the `Ghost<Seq<A>>` field `seq` and to the
    //     `Array::view()` inline form.
    lemma_array_set_det_seq_field_eq::<A, N>(
        pre_self_, i, out, post1_self_, post2_self_,
    );
    assert(post1_self_.seq@ =~= post2_self_.seq@);
    assert(post1_self_.seq@ == post2_self_.seq@);
    assert(post1_self_.seq === post2_self_.seq);
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_@ == post2_self_@);

    // (2) Pointwise equality of the `[A;N]` arrays.  We connect the
    //     two views via the inline `Array::view()` (== `self.seq@`)
    //     and `lemma_array_index` (broadcast), giving us
    //     `a[j] == a.view()[j]` for `0 <= j < N`.
    assert forall|j: int| 0 <= j < N implies
        #[trigger] post1_self_.ar[j] == #[trigger] post2_self_.ar[j]
    by {
        // `a[j] == a.view()[j]` via lemma_array_index (broadcast).
        assert(post1_self_.ar[j] == post1_self_.ar.view()[j]);
        assert(post2_self_.ar[j] == post2_self_.ar.view()[j]);
        // The inline `Array::view()` is `self.seq@`, so the seq
        // equality from (1) gives `post1_self_@[j] == post2_self_@[j]`.
        assert(post1_self_@[j] == post2_self_@[j]);
    };

    // (3) Lift pointwise `ar` equality to `=~=` and then to `==`.
    lemma_array_ar_ext_eq::<A, N>(post1_self_.ar, post2_self_.ar);
    assert(post1_self_.ar =~= post2_self_.ar);
    assert(post1_self_.ar == post2_self_.ar);
    assert(post1_self_.ar === post2_self_.ar);

    // (4) Combine the two field equalities into full struct equality.
    lemma_array_eq_from_fields::<A, N>(post1_self_, post2_self_);
    assert(post1_self_ =~= post2_self_);
    assert(post1_self_ == post2_self_);

    // (5) Unit-typed return values are trivially equal.
    assert(r1 == ());
    assert(r2 == ());
    assert(r1 == r2);

    // (6) Close out the determinism predicate explicitly.
    assert(det_set_equal(r1, r2, post1_self_, post2_self_));
}

// Trivial fact about unit returns, valid whether or not the
// antecedent fires; gives z3 the `r1 == r2` conjunct unconditionally.
assert(r1 == r2);

helper_lemmas:
// Helper 1.  Drive Seq extensionality through the shared
// `pre_self_.seq@.update(i as int, out)` target and lift the resulting
// `Seq<A>` equality up to the `Ghost<Seq<A>>` field `seq`.  Verus
// converts `=~=` to `==` for `Seq<_>`, and `Ghost<T>` equality is tied
// structurally to its `@` projection, so `seq@ == seq@` lifts cleanly
// to `seq === seq`.
proof fn lemma_array_set_det_seq_field_eq<A, const N: usize>(
    pre_self_: Array<A, N>,
    i: usize,
    out: A,
    post1: Array<A, N>,
    post2: Array<A, N>,
)
    requires
        post1.seq@ =~= pre_self_.seq@.update(i as int, out),
        post2.seq@ =~= pre_self_.seq@.update(i as int, out),
    ensures
        post1.seq@ =~= post2.seq@,
        post1.seq@ == post2.seq@,
        post1.seq === post2.seq,
        post1@ =~= post2@,
        post1@ == post2@,
{
    assert(post1.seq@ =~= post2.seq@);
    assert(post1.seq@ == post2.seq@);
}

// Helper 2.  Bridge per-field equality on `Array<A, N>` to full struct
// equality.  `Array<A, N>` has exactly two `pub` fields (`seq` and `ar`),
// so structural equality decomposes field-wise and Verus discharges this
// lemma directly from its struct-equality axiom with an empty body.
proof fn lemma_array_eq_from_fields<A, const N: usize>(
    a1: Array<A, N>,
    a2: Array<A, N>,
)
    requires
        a1.seq === a2.seq,
        a1.ar === a2.ar,
    ensures
        a1 == a2,
        a1 =~= a2,
{
}

// Helper 3.  Lift pointwise `[A;N]` element equality to extensional
// (and hence propositional) equality via `axiom_array_ext_equal`.
proof fn lemma_array_ar_ext_eq<A, const N: usize>(
    a1: [A; N],
    a2: [A; N],
)
    requires
        forall|j: int| 0 <= j < N ==> #[trigger] a1[j] == #[trigger] a2[j],
    ensures
        a1 =~= a2,
        a1 == a2,
        a1 === a2,
{
    broadcast use vstd::array::group_array_axioms;
    assert(a1 =~= a2);
}
